import request from '@/utils/request'

/**
 * 分页查询用户列表
 * @param {Object} params - 查询参数 { current, size, username, status }
 */
export function getUserPage(params) {
    return request({
        url: '/sys/user/page', // 这里可以改成你后端实际的接口地址
        method: 'get',
        params
    })
}

/**
 * 修改用户状态（启用/停用）
 * @param {Long} id - 用户ID
 * @param {Integer} status - 新状态 (0:停用, 1:正常)
 */
export function updateUserStatus(id, status) {
    return request({
        url: `/sys/user/status/${id}/${status}`,
        method: 'put'
    })
}
